INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_B1_01','content','/ˈkɒntent/','noun','콘텐츠, 미디어 소재','Material created for online audiences, including video, text, and images.','Creating quality {content} requires planning and consistency.','양질의 콘텐츠를 만들려면 계획과 꾸준함이 필요해요.','content','B1','media',1,'content strategy planning camera filming studio'),
('w_media_B1_02','influencer','/ˈɪnfluənsər/','noun','인플루언서','A person with many social media followers who can influence buying decisions.','She partnered with a popular {influencer} for the campaign.','그녀는 캠페인을 위해 유명 인플루언서와 협력했어요.','influencer','B1','media',1,'influencer marketing brand deal social media'),
('w_media_B1_03','platform','/ˈplætfɔːrm/','noun','플랫폼','An online service or website where users create and share content.','Which {platform} do you use the most?','어떤 플랫폼을 가장 많이 사용해요?','platform','B1','media',1,'social media platforms icons logos apps'),
('w_media_B1_04','viral','/ˈvaɪrəl/','noun (derived)','바이럴','Something that spreads rapidly across the internet.','The campaign went {viral} within hours.','그 캠페인은 몇 시간 만에 바이럴됐어요.','viral','B1','media',1,'viral campaign trending social media exponential'),
('w_media_B1_05','algorithm','/ˈælɡərɪðəm/','noun','알고리즘','A set of rules a platform uses to decide what content to show users.','The {algorithm} rewards consistent posting.','알고리즘은 꾸준한 게시를 선호해요.','algorithm','B1','media',1,'algorithm recommendation feed content youtube'),
('w_media_B1_06','trending','/ˈtrendɪŋ/','adjective','트렌딩의, 유행하는','Currently popular and widely discussed on social media or news.','That topic has been {trending} all week.','그 주제가 일주일 내내 트렌딩이에요.','trending','B1','media',1,'trending topic twitter hashtag social media'),
('w_media_B1_07','hashtag','/ˈhæʃtæɡ/','noun','해시태그 (전략적 사용)','A labeling tool used to categorize content and improve discoverability.','Use relevant {hashtags} to reach a wider audience.','더 많은 사람들에게 닿으려면 관련 해시태그를 써요.','hashtags','B1','media',1,'hashtag strategy instagram reach discoverability'),
('w_media_B1_08','engagement','/ɪnˈɡeɪdʒmənt/','noun','참여도, 인게이지먼트','The level of interaction (likes, comments, shares) a post receives.','High {engagement} signals quality content to the algorithm.','높은 참여도는 알고리즘에 양질의 콘텐츠라는 신호를 줘요.','engagement','B1','media',1,'engagement rate likes comments shares analytics'),
('w_media_B1_09','broadcast','/ˈbrɔːdkæst/','verb','방송하다','To transmit a programme to many people via radio, TV, or online.','The event was {broadcast} live on all major channels.','그 행사는 모든 주요 채널에서 생방송됐어요.','broadcast','B1','media',1,'live broadcast television news anchor studio'),
('w_media_B1_10','podcast','/ˈpɒdkæst/','verb','팟캐스트로 내보내다','To produce and distribute audio episodes online.','She started {podcasting} about personal finance.','그녀는 개인 재무에 관한 팟캐스트를 시작했어요.','podcasting','B1','media',1,'podcasting microphone recording studio episode'),
('w_media_B1_11','clickbait','/ˈklɪkbeɪt/','noun','낚시성 제목','A sensational or misleading headline designed to attract clicks.','That article headline is pure {clickbait}.','그 기사 제목은 완전 낚시예요.','clickbait','B1','media',1,'clickbait headline sensational news article link'),
('w_media_B1_12','thumbnail','/ˈθʌmbneɪl/','noun','썸네일','A small preview image representing a video or post.','A good {thumbnail} can double your click-through rate.','좋은 썸네일은 클릭률을 두 배로 높일 수 있어요.','thumbnail','B1','media',1,'youtube thumbnail design video preview click'),
('w_media_B1_13','caption','/ˈkæpʃən/','verb','캡션을 달다, 설명하다','To write text describing an image or adding context.','She carefully {captioned} each photo with a story.','그녀는 각 사진에 신중하게 이야기를 담은 캡션을 달았어요.','captioned','B1','media',2,'writing caption instagram storytelling photo post'),
('w_media_B1_14','recommend','/ˌrekəˈmend/','verb','추천하다 (콘텐츠)','To suggest content worth watching or reading.','The app {recommends} videos based on your watch history.','앱은 시청 기록을 바탕으로 영상을 추천해요.','recommends','B1','media',1,'recommendation engine youtube watch history suggest'),
('w_media_B1_15','reaction','/riˈækʃən/','noun','반응 영상','A video in which someone responds to existing content.','His {reaction} video to the trailer got more views than the original.','예고편에 대한 그의 반응 영상이 원본보다 더 많은 조회수를 받았어요.','reaction','B1','media',2,'reaction video youtube trailer watching face'),
('w_media_B1_16','subscriber','/səbˈskraɪbər/','noun','구독자','A person who subscribes to a channel or newsletter.','She reached one million {subscribers} this year.','그녀는 올해 구독자 백만 명을 달성했어요.','subscribers','B1','media',1,'one million subscribers youtube creator celebration'),
('w_media_B1_17','collaboration','/kəˌlæbəˈreɪʃən/','noun','콜라보, 협업','Two or more creators working together on content.','The {collaboration} between the two YouTubers doubled both audiences.','두 유튜버의 콜라보로 양측 시청자가 두 배 늘었어요.','collaboration','B1','media',1,'collaboration youtuber collab filming together studio'),
('w_media_B1_18','monetize','/ˈmɒnɪtaɪz/','verb','수익화하다','To earn money from a channel or online content.','You need 1,000 subscribers before you can {monetize}.','수익화하려면 구독자 천 명이 필요해요.','monetize','B1','media',1,'monetize youtube earnings channel income revenue'),
('w_media_B1_19','analytics','/ˌænəˈlɪtɪks/','noun','분석 데이터','Data showing how content performs (views, reach, retention).','Check your {analytics} to see what your audience enjoys.','어떤 콘텐츠를 좋아하는지 분석 데이터를 확인해 보세요.','analytics','B1','media',1,'analytics dashboard graph data social media insights'),
('w_media_B1_20','reach','/riːtʃ/','noun','도달 범위','The total number of unique people who see a piece of content.','The campaign had a {reach} of over five million.','그 캠페인의 도달 범위는 오백만 이상이었어요.','reach','B1','media',1,'reach metric social media campaign statistics chart'),
('w_media_B1_21','niche','/niːʃ/','noun','틈새 분야','A specialized area of interest that attracts a specific audience.','Finding your {niche} is key to growing an audience.','자신의 틈새 분야를 찾는 것이 청중을 키우는 핵심이에요.','niche','B1','media',1,'niche content creator specific audience hobby channel'),
('w_media_B1_22','format','/ˈfɔːrmæt/','noun','포맷, 형식','The structure and style of a media piece.','Experiment with different {formats} to see what works.','어떤 게 효과적인지 다양한 포맷을 시험해 보세요.','formats','B1','media',2,'video format style different short long tutorial'),
('w_media_B1_23','brand deal','/brænd diːl/','noun','브랜드 딜, 광고 협찬','A paid partnership between a creator and a company.','She disclosed her {brand deal} in the video description.','그녀는 영상 설명에 브랜드 딜을 공개했어요.','brand deal','B1','media',1,'brand deal sponsorship disclosure influencer product'),
('w_media_B1_24','comment section','/ˈkɒment ˌsekʃən/','noun','댓글 창','The area below a video or post where users leave comments.','The {comment section} was filled with debate.','댓글 창은 논쟁으로 가득했어요.','comment section','B1','media',2,'comment section debate youtube controversial'),
('w_media_B1_25','binge','/bɪndʒ/','verb','몰아보다','To watch many episodes of a show in a short time.','I {binged} the whole series in one weekend.','주말 동안 시리즈 전편을 몰아봤어요.','binged','B1','media',1,'binge watching netflix series sofa night cozy'),
('w_media_B1_26','go live','/ɡoʊ laɪv/','phrase','라이브 방송을 시작하다','To begin a real-time broadcast on a social media platform.','She {went live} to answer questions from fans.','그녀는 팬들의 질문에 답하기 위해 라이브를 켰어요.','went live','B1','media',2,'going live instagram fans questions real time'),
('w_media_B1_27','retweet','/ˌriːˈtwiːt/','verb','리트윗하다','To share another user''s tweet to your own followers.','The celebrity {retweeted} the fan''s message.','그 셀럽은 팬의 메시지를 리트윗했어요.','retweeted','B1','media',2,'retweet twitter celebrity fan viral'),
('w_media_B1_28','unboxing','/ˌʌnˈbɒksɪŋ/','noun','언박싱','A type of video showing someone opening a new product.','His {unboxing} video of the new console got five million views.','그의 새 콘솔 언박싱 영상은 오백만 조회수를 받았어요.','unboxing','B1','media',2,'unboxing video product new box opening hands'),
('w_media_B1_29','tutorial','/tjuːˈtɔːriəl/','noun','튜토리얼','An instructional video or guide teaching a skill.','I learned the skill from a YouTube {tutorial}.','유튜브 튜토리얼로 그 기술을 배웠어요.','tutorial','B1','media',1,'tutorial youtube learning skill how-to video'),
('w_media_B1_30','vlog','/vlɒɡ/','noun','브이로그','A video diary or journal shared online.','She documents her travels in a weekly {vlog}.','그녀는 주간 브이로그로 여행을 기록해요.','vlog','B1','media',1,'vlog travel daily life camera selfie stick'),
('w_media_B1_31','demographic','/ˌdeməˈɡræfɪk/','noun','인구통계, 타깃 시청자','A specific group of people sharing characteristics targeted by media.','The show''s {demographic} is mostly teens and young adults.','그 쇼의 타깃 시청자는 주로 10대와 청년층이에요.','demographic','B1','media',2,'target audience demographic age group chart'),
('w_media_B1_32','spoiler','/ˈspɔɪlər/','noun','스포일러','Information that reveals key plot points before someone has seen/read them.','Warning: this review contains {spoilers}.','경고: 이 리뷰에는 스포일러가 포함되어 있어요.','spoilers','B1','media',2,'spoiler warning movie review no spoiler banner'),
('w_media_B1_33','streaming service','/ˈstriːmɪŋ ˈsɜːrvɪs/','noun','스트리밍 서비스','An online platform that provides on-demand audio or video content.','Which {streaming service} do you subscribe to?','어떤 스트리밍 서비스 구독해요?','streaming service','B1','media',1,'netflix spotify streaming service logo subscription'),
('w_media_B1_34','verified','/ˈverɪfaɪd/','adjective','인증된','Having a badge confirming authenticity on a social media account.','Getting {verified} on Instagram boosts credibility.','인스타그램에서 인증 받으면 신뢰도가 올라가요.','verified','B1','media',2,'verified blue checkmark instagram account badge'),
('w_media_B1_35','clip','/klɪp/','verb','클립으로 잘라내다','To extract a short segment from a longer video.','He {clipped} the funniest moments for his highlights.','그는 가장 재미있는 순간들을 클립으로 잘라 하이라이트를 만들었어요.','clipped','B1','media',2,'clipping video highlights editing short cut');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_B2_01','misinformation','/ˌmɪsɪnfərˈmeɪʃən/','noun','잘못된 정보','False or inaccurate information spread without deliberate intent to deceive.','Social media accelerates the spread of {misinformation}.','소셜 미디어는 잘못된 정보의 확산을 가속화해요.','misinformation','B2','media',1,'misinformation fake news spread social media warning'),
('w_media_B2_02','disinformation','/ˌdɪsɪnfərˈmeɪʃən/','noun','허위 정보','False information deliberately spread to deceive people.','State-sponsored {disinformation} campaigns target voters.','국가 주도의 허위 정보 캠페인은 유권자를 타깃으로 해요.','disinformation','B2','media',1,'disinformation propaganda fake news government media'),
('w_media_B2_03','clickbait','/ˈklɪkbeɪt/','verb (derived)','낚시 기사를 쓰다','To produce content with misleading headlines to attract clicks.','Many news outlets resort to {clickbait} to survive.','많은 언론사들이 살아남기 위해 낚시성 기사에 의존해요.','clickbait','B2','media',1,'clickbait headline news outlet sensational media'),
('w_media_B2_04','polarization','/ˌpoʊlərɪˈzeɪʃən/','noun','양극화','The process of dividing into two opposing groups with extreme views.','Social media contributes to political {polarization}.','소셜 미디어는 정치적 양극화에 기여해요.','polarization','B2','media',1,'political polarization divided groups social media debate'),
('w_media_B2_05','narrative','/ˈnærətɪv/','noun','서사, 담론','The particular way a story or series of events is described or interpreted.','The media shapes the {narrative} around public events.','미디어는 공공 사건에 대한 서사를 형성해요.','narrative','B2','media',1,'media narrative storytelling news framing bias'),
('w_media_B2_06','curate','/kjʊˈreɪt/','verb','큐레이션하다','To carefully select and organize content for a specific audience.','She {curates} a daily newsletter of the best tech news.','그녀는 매일 최고의 기술 뉴스 뉴스레터를 큐레이션해요.','curates','B2','media',1,'curating content newsletter best selection editorial'),
('w_media_B2_07','monetize','/ˈmɒnɪtaɪz/','verb','수익화 전략을 세우다','To develop revenue streams from digital content or platforms.','The startup is looking for ways to {monetize} user data.','그 스타트업은 사용자 데이터를 수익화할 방법을 찾고 있어요.','monetize','B2','media',1,'monetize data startup revenue business model digital'),
('w_media_B2_08','analytics','/ˌænəˈlɪtɪks/','noun','고급 분석','Advanced data analysis used to understand audience behaviour.','Deep {analytics} reveal when your audience is most active.','심층 분석을 통해 청중이 가장 활발한 시간대를 알 수 있어요.','analytics','B2','media',1,'deep analytics dashboard data visualization insight'),
('w_media_B2_09','demographic','/ˌdeməˈɡræfɪk/','adjective','인구통계학적인','Relating to the structure of populations in terms of age, gender, etc.','The platform shifted its {demographic} focus to older users.','그 플랫폼은 인구통계학적 초점을 고령층으로 바꿨어요.','demographic','B2','media',1,'demographic shift older users platform age graph'),
('w_media_B2_10','reach','/riːtʃ/','verb','도달하다 (미디어)','To successfully communicate with or influence a target audience.','The campaign aimed to {reach} young voters.','그 캠페인은 젊은 유권자들에게 닿는 것을 목표로 했어요.','reach','B2','media',1,'campaign reaching young voters media strategy'),
('w_media_B2_11','echo chamber','/ˈekoʊ ˌtʃeɪmbər/','noun','에코 챔버, 정보의 거품','An environment where people only encounter views that reinforce their own.','Social media algorithms can trap users in an {echo chamber}.','소셜 미디어 알고리즘이 사용자를 에코 챔버에 가두기도 해요.','echo chamber','B2','media',1,'echo chamber bubble social media algorithm opinions'),
('w_media_B2_12','filter bubble','/ˈfɪltər ˌbʌbəl/','noun','필터 버블','A state of intellectual isolation caused by personalised content.','We need to burst our {filter bubble} and seek diverse news.','필터 버블을 깨고 다양한 뉴스를 접해야 해요.','filter bubble','B2','media',1,'filter bubble personalization algorithm isolation diverse'),
('w_media_B2_13','fact-check','/ˈfækt tʃek/','verb','팩트체크하다','To verify the accuracy of a claim or piece of information.','Always {fact-check} before sharing news online.','온라인에서 뉴스를 공유하기 전에 항상 팩트체크하세요.','fact-check','B2','media',1,'fact checking news media accuracy verification research'),
('w_media_B2_14','media literacy','/ˈmiːdiə ˌlɪtərəsi/','noun','미디어 리터러시','The ability to critically analyze and evaluate media messages.','Schools should teach {media literacy} from an early age.','학교에서는 어릴 때부터 미디어 리터러시를 가르쳐야 해요.','media literacy','B2','media',1,'media literacy education critical thinking news students'),
('w_media_B2_15','algorithm bias','/ˈælɡərɪðəm baɪəs/','noun','알고리즘 편향','When a recommendation system systematically favours certain viewpoints.','Researchers found evidence of {algorithm bias} on the platform.','연구자들은 그 플랫폼에서 알고리즘 편향의 증거를 발견했어요.','algorithm bias','B2','media',1,'algorithm bias AI fairness data skewed results'),
('w_media_B2_16','credibility','/ˌkredɪˈbɪlɪti/','noun','신뢰성','The quality of being trusted and believed as accurate.','A journalist''s {credibility} is their most valuable asset.','저널리스트의 신뢰성은 가장 소중한 자산이에요.','credibility','B2','media',1,'credibility journalist trust media source reliable'),
('w_media_B2_17','bias','/ˈbaɪəs/','noun','편향','Inclination or prejudice in favour of or against something.','Every news outlet has some degree of editorial {bias}.','모든 언론사에는 어느 정도의 편집 편향이 있어요.','bias','B2','media',1,'media bias editorial perspective lean news'),
('w_media_B2_18','censorship','/ˈsensərʃɪp/','noun','검열','The suppression of content deemed objectionable or harmful.','Critics accused the government of internet {censorship}.','비평가들은 정부를 인터넷 검열로 비난했어요.','censorship','B2','media',1,'censorship internet blocked government freedom press'),
('w_media_B2_19','algorithm','/ˈælɡərɪðəm/','noun','알고리즘 (플랫폼 전략)','The complex system determining what content appears in user feeds.','Understanding the {algorithm} is key to growing online.','알고리즘을 이해하는 것이 온라인에서 성장하는 핵심이에요.','algorithm','B2','media',1,'algorithm code data platform content recommendation'),
('w_media_B2_20','influencer marketing','/ˈɪnfluənsər ˈmɑːrkɪtɪŋ/','noun','인플루언서 마케팅','A strategy using popular social media figures to promote products.','Brands now invest heavily in {influencer marketing}.','브랜드들은 이제 인플루언서 마케팅에 대규모 투자를 해요.','influencer marketing','B2','media',1,'influencer marketing brand partnership sponsored content'),
('w_media_B2_21','deepfake','/ˈdiːpfeɪk/','noun','딥페이크','Synthetic media using AI to replace someone''s likeness in video.','A {deepfake} video of the politician circulated online.','그 정치인의 딥페이크 영상이 온라인에 퍼졌어요.','deepfake','B2','media',1,'deepfake AI fake video face swap synthetic media'),
('w_media_B2_22','transparency','/trænsˈpærənsi/','noun','투명성','Openness about how decisions, including content choices, are made.','The platform was called out for a lack of {transparency}.','그 플랫폼은 투명성 부족으로 비난을 받았어요.','transparency','B2','media',1,'transparency platform content policy trust accountability'),
('w_media_B2_23','engagement rate','/ɪnˈɡeɪdʒmənt reɪt/','noun','참여율','The percentage of followers who interact with a post.','An {engagement rate} above 3% is considered healthy.','참여율 3% 이상은 양호한 것으로 여겨져요.','engagement rate','B2','media',1,'engagement rate analytics instagram metric performance'),
('w_media_B2_24','content moderation','/ˈkɒntent ˌmɒdəˈreɪʃən/','noun','콘텐츠 중재','The process of monitoring and enforcing platform rules.','{Content moderation} is increasingly handled by AI.','콘텐츠 중재는 점점 더 AI가 담당하고 있어요.','content moderation','B2','media',1,'content moderation AI flag remove policy platform'),
('w_media_B2_25','virality','/vaɪˈræləti/','noun','바이럴성','The quality of spreading rapidly across social networks.','The ad''s {virality} surprised even the marketing team.','그 광고의 바이럴성은 마케팅 팀조차 놀라게 했어요.','virality','B2','media',1,'virality social media ad campaign surprise spread'),
('w_media_B2_26','cancel culture','/ˈkænsəl ˌkʌltʃər/','noun','캔슬 컬처','The practice of withdrawing support from public figures for offensive behaviour.','The debate around {cancel culture} divides opinions online.','캔슬 컬처를 둘러싼 논쟁이 온라인에서 의견을 나누고 있어요.','cancel culture','B2','media',1,'cancel culture debate social media public figure'),
('w_media_B2_27','comment moderation','/ˈkɒment ˌmɒdəˈreɪʃən/','noun','댓글 관리','The review and removal of harmful or abusive user comments.','Better {comment moderation} could reduce online hate speech.','더 나은 댓글 관리로 온라인 혐오 발언을 줄일 수 있어요.','comment moderation','B2','media',2,'comment moderation hate speech online safety platform'),
('w_media_B2_28','algorithm-driven','/ˈælɡərɪðəm ˌdrɪvən/','adjective','알고리즘 기반의','Controlled or determined by automated computational rules.','Our news experience has become entirely {algorithm-driven}.','우리의 뉴스 경험은 완전히 알고리즘 기반이 됐어요.','algorithm-driven','B2','media',2,'algorithm driven news feed automated personalised'),
('w_media_B2_29','news cycle','/njuːz ˈsaɪkəl/','noun','뉴스 사이클','The time it takes for a story to appear, peak, and disappear from media.','Politicians now exploit the 24-hour {news cycle}.','정치인들은 이제 24시간 뉴스 사이클을 이용해요.','news cycle','B2','media',1,'24 hour news cycle media coverage fast changing'),
('w_media_B2_30','platform economy','/ˈplætfɔːrm ɪˈkɒnəmi/','noun','플랫폼 경제','An economic model where value is created through digital platforms.','The {platform economy} has disrupted traditional industries.','플랫폼 경제가 전통 산업을 혁신해 왔어요.','platform economy','B2','media',1,'platform economy disruption digital gig creator'),
('w_media_B2_31','data privacy','/ˈdeɪtə ˈprɪvəsi/','noun','데이터 프라이버시','The right of individuals to control how their personal data is used.','Users are increasingly concerned about {data privacy}.','사용자들은 데이터 프라이버시에 대한 우려가 점점 커지고 있어요.','data privacy','B2','media',1,'data privacy GDPR personal information protection'),
('w_media_B2_32','sensationalism','/senˈseɪʃənəlɪzəm/','noun','선정주의','The use of shocking or exaggerated stories to attract attention.','Tabloid journalism often relies on {sensationalism}.','타블로이드 저널리즘은 종종 선정주의에 의존해요.','sensationalism','B2','media',1,'sensationalism tabloid headline shocking exaggerated news'),
('w_media_B2_33','public opinion','/ˈpʌblɪk əˈpɪnjən/','noun','여론','The collective views held by a large number of people on a topic.','Social media now shapes {public opinion} faster than ever.','소셜 미디어가 이제 그 어느 때보다 빠르게 여론을 형성해요.','public opinion','B2','media',1,'public opinion poll social media influence speed'),
('w_media_B2_34','editorial','/ˌedɪˈtɔːriəl/','noun','사설, 편집의','An article expressing the opinion of a publication.','The newspaper ran a critical {editorial} on the policy.','그 신문은 정책에 비판적인 사설을 실었어요.','editorial','B2','media',1,'editorial newspaper opinion page critical analysis'),
('w_media_B2_35','press freedom','/pres ˈfriːdəm/','noun','언론의 자유','The freedom of journalists and news organisations to report without restriction.','Journalists worldwide fight to protect {press freedom}.','전 세계 기자들은 언론의 자유를 지키기 위해 싸우고 있어요.','press freedom','B2','media',1,'press freedom journalism protest newspaper freedom');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_C1_01','media literacy','/ˈmiːdiə ˌlɪtərəsi/','noun','미디어 리터러시','The capacity to access, analyze, evaluate, and create media messages.','Developing {media literacy} is essential in today''s information landscape.','오늘날의 정보 환경에서 미디어 리터러시를 키우는 것은 필수예요.','media literacy','C1','media',1,'media literacy critical thinking news analysis skills'),
('w_media_C1_02','propaganda','/ˌprɒpəˈɡændə/','noun','선전, 프로파간다','Information, especially biased, used to promote a political cause.','State-run media often functions as a vehicle for {propaganda}.','국가 운영 미디어는 종종 선전의 수단으로 기능해요.','propaganda','C1','media',1,'propaganda poster government media bias political'),
('w_media_C1_03','surveillance','/sərˈveɪləns/','noun','감시 (디지털)','The monitoring of behaviour and communications, especially online.','Mass digital {surveillance} raises serious privacy concerns.','대규모 디지털 감시는 심각한 프라이버시 우려를 낳아요.','surveillance','C1','media',1,'surveillance cameras CCTV digital monitoring privacy'),
('w_media_C1_04','censorship','/ˈsensərʃɪp/','noun','검열 (비판적 관점)','The suppression of speech or information considered harmful or politically inconvenient.','Internet {censorship} is expanding in authoritarian states.','인터넷 검열이 권위주의 국가에서 확대되고 있어요.','censorship','C1','media',1,'internet censorship authoritarian block firewall freedom'),
('w_media_C1_05','epistemology','/ɪˌpɪstɪˈmɒlədʒi/','noun','인식론','The branch of philosophy concerned with how we know what we know.','The post-truth era challenges our media {epistemology}.','탈진실 시대는 우리의 미디어 인식론에 도전장을 내밀어요.','epistemology','C1','media',1,'epistemology knowledge philosophy truth media information'),
('w_media_C1_06','discourse','/ˈdɪskɔːrs/','noun','담론','A way of talking about or representing a subject that shapes understanding.','The public {discourse} around AI is often distorted by media.','AI에 관한 공론장 담론은 미디어에 의해 종종 왜곡돼요.','discourse','C1','media',1,'public discourse debate media analysis social conversation'),
('w_media_C1_07','hegemony','/hɪˈɡeməni/','noun','헤게모니','Dominance by one group over others, especially in cultural or media terms.','Media {hegemony} shapes which stories get told globally.','미디어 헤게모니는 어떤 이야기가 전 세계적으로 전달될지 형성해요.','hegemony','C1','media',1,'media hegemony global dominance power cultural influence'),
('w_media_C1_08','gatekeeping','/ˈɡeɪtkiːpɪŋ/','noun','게이트키핑','The process of controlling access to information in the media.','Social media has disrupted traditional journalistic {gatekeeping}.','소셜 미디어는 전통적인 저널리즘의 게이트키핑을 혼란에 빠뜨렸어요.','gatekeeping','C1','media',1,'gatekeeping journalism editor media power information'),
('w_media_C1_09','framing','/ˈfreɪmɪŋ/','noun','프레이밍, 틀짓기','The process by which media shapes how issues are perceived.','The {framing} of immigration as a crisis influences public opinion.','이민을 위기로 프레이밍하는 것이 여론에 영향을 줘요.','framing','C1','media',1,'media framing immigration news coverage bias perspective'),
('w_media_C1_10','agenda-setting','/əˈdʒendə ˌsetɪŋ/','noun','의제 설정','The media''s power to influence which issues the public considers important.','News editors engage in {agenda-setting} every day.','뉴스 편집자들은 매일 의제 설정을 해요.','agenda-setting','C1','media',1,'agenda setting media power news editorial priority'),
('w_media_C1_11','manufactured consent','/ˌmænjʊˈfæktʃərd kənˈsent/','noun','동의 조작','The systematic shaping of public opinion by elites through media.','Noam Chomsky described {manufactured consent} in mass media.','노암 촘스키는 대중 매체에서의 동의 조작을 설명했어요.','manufactured consent','C1','media',1,'manufactured consent Chomsky media elite propaganda'),
('w_media_C1_12','disinformation warfare','/ˌdɪsɪnfərˈmeɪʃən ˈwɔːrfer/','noun','허위정보 전쟁','The strategic use of false information as a tool of geopolitical conflict.','Several nations engage in {disinformation warfare} online.','여러 국가들이 온라인에서 허위정보 전쟁을 벌이고 있어요.','disinformation warfare','C1','media',1,'information warfare geopolitics online fake news strategy'),
('w_media_C1_13','participatory media','/pɑːˌtɪsɪpətɔːri ˈmiːdiə/','noun','참여적 미디어','Media forms that enable active audience engagement and content creation.','Blogs were the first wave of {participatory media}.','블로그는 참여적 미디어의 첫 번째 물결이었어요.','participatory media','C1','media',2,'participatory media blog user generated content web'),
('w_media_C1_14','algorithmic amplification','/ˌælɡərɪðmɪk ˌæmplɪfɪˈkeɪʃən/','noun','알고리즘 증폭','The process by which platforms boost the spread of certain content.','Outrage content benefits from {algorithmic amplification}.','분노 유발 콘텐츠는 알고리즘 증폭으로 이득을 봐요.','algorithmic amplification','C1','media',1,'algorithm amplification outrage viral spread content boost'),
('w_media_C1_15','media convergence','/ˈmiːdiə kənˈvɜːrdʒəns/','noun','미디어 융합','The merging of different media forms through digital technology.','The smartphone is a symbol of {media convergence}.','스마트폰은 미디어 융합의 상징이에요.','media convergence','C1','media',2,'media convergence smartphone digital all-in-one platform'),
('w_media_C1_16','infodemic','/ˌɪnfoʊˈdemɪk/','noun','인포데믹','An overabundance of information, especially online misinformation during a crisis.','The WHO warned of an {infodemic} alongside the pandemic.','WHO는 팬데믹과 함께 인포데믹을 경고했어요.','infodemic','C1','media',1,'infodemic misinformation pandemic overload news'),
('w_media_C1_17','platform governance','/ˈplætfɔːrm ˈɡʌvərnəns/','noun','플랫폼 거버넌스','The rules and systems by which online platforms manage their communities.','Calls for better {platform governance} are growing louder.','더 나은 플랫폼 거버넌스를 요구하는 목소리가 커지고 있어요.','platform governance','C1','media',1,'platform governance regulation tech policy law rules'),
('w_media_C1_18','soft power','/sɒft ˈpaʊər/','noun','소프트 파워','The ability to influence others through cultural appeal rather than force.','Global streaming platforms are tools of cultural {soft power}.','글로벌 스트리밍 플랫폼은 문화적 소프트 파워의 도구예요.','soft power','C1','media',1,'soft power culture Netflix streaming global influence'),
('w_media_C1_19','attention economy','/əˈtenʃən ɪˈkɒnəmi/','noun','관심 경제','An economic model based on capturing and monetizing users'' attention.','Platforms compete fiercely in the {attention economy}.','플랫폼들은 관심 경제에서 치열하게 경쟁해요.','attention economy','C1','media',1,'attention economy screen time engagement addictive design'),
('w_media_C1_20','digital colonialism','/ˈdɪdʒɪtəl kəˈloʊniəlɪzəm/','noun','디지털 식민주의','The dominance of Western tech companies over global digital infrastructure.','Critics warn of {digital colonialism} by Silicon Valley giants.','비평가들은 실리콘 밸리 거대 기업들의 디지털 식민주의를 경고해요.','digital colonialism','C1','media',1,'digital colonialism silicon valley global tech power'),
('w_media_C1_21','counter-narrative','/ˈkaʊntər ˌnærətɪv/','noun','대항 서사','A competing story that challenges the dominant media narrative.','Activists use social media to spread {counter-narratives}.','활동가들은 소셜 미디어를 이용해 대항 서사를 퍼뜨려요.','counter-narratives','C1','media',2,'counter narrative activism social media alternative story'),
('w_media_C1_22','media pluralism','/ˈmiːdiə ˈplʊərəlɪzəm/','noun','미디어 다원주의','A diversity of independent media outlets presenting different viewpoints.','True democracy requires {media pluralism}.','진정한 민주주의는 미디어 다원주의를 필요로 해요.','media pluralism','C1','media',2,'media pluralism diversity news outlets viewpoints democracy'),
('w_media_C1_23','techno-optimism','/ˈteknəʊ ˈɒptɪmɪzəm/','noun','기술 낙관주의','The belief that technology will solve social and media problems.','Critics argue that {techno-optimism} ignores structural harms.','비평가들은 기술 낙관주의가 구조적 해악을 외면한다고 주장해요.','techno-optimism','C1','media',2,'techno optimism silicon valley future technology belief'),
('w_media_C1_24','news deserts','/njuːz ˈdezərts/','noun','뉴스 사막','Areas with little or no local journalism coverage.','Hundreds of US counties have become {news deserts}.','미국 수백 개 군이 뉴스 사막이 됐어요.','news deserts','C1','media',2,'news deserts local journalism decline community newspaper'),
('w_media_C1_25','moral panic','/ˈmɒrəl ˈpænɪk/','noun','도덕적 공황','An exaggerated social reaction to a perceived threat driven by media coverage.','Each new social media platform causes a {moral panic}.','새로운 소셜 미디어 플랫폼이 나올 때마다 도덕적 공황이 생겨요.','moral panic','C1','media',2,'moral panic social media technology fear parents media'),
('w_media_C1_26','co-creation','/ˌkoʊ kriˈeɪʃən/','noun','공동 창작','The joint production of content by creators and their audiences.','Fan fiction is a form of {co-creation} with media properties.','팬픽션은 미디어 자산과의 공동 창작 형태예요.','co-creation','C1','media',2,'co-creation fan fiction collaboration community content'),
('w_media_C1_27','cross-platform strategy','/krɒs ˈplætfɔːrm ˈstrætədʒi/','noun','크로스 플랫폼 전략','A content plan that distributes material across multiple channels.','A successful {cross-platform strategy} maximizes audience reach.','성공적인 크로스 플랫폼 전략은 청중 도달 범위를 극대화해요.','cross-platform strategy','C1','media',2,'cross platform strategy social media distribution channels'),
('w_media_C1_28','mediatization','/ˌmiːdiətaɪˈzeɪʃən/','noun','미디어화','The process by which society is increasingly shaped by media logic.','Politics has undergone profound {mediatization} since the 1990s.','정치는 1990년대 이후 깊은 미디어화를 겪어왔어요.','mediatization','C1','media',2,'mediatization politics society media logic television'),
('w_media_C1_29','networked journalism','/ˈnetwɜːrkt ˈdʒɜːrnəlɪzəm/','noun','네트워크 저널리즘','Journalism that involves collaboration between professionals and citizens online.','{Networked journalism} blurs the line between reporter and public.','네트워크 저널리즘은 기자와 대중 사이의 경계를 흐려요.','networked journalism','C1','media',2,'networked journalism citizen reporter online collaboration'),
('w_media_C1_30','digital public sphere','/ˈdɪdʒɪtəl ˌpʌblɪk sfɪər/','noun','디지털 공론장','An online space where citizens debate and form public opinion.','Twitter once promised to be a {digital public sphere}.','트위터는 한때 디지털 공론장이 될 것을 약속했어요.','digital public sphere','C1','media',1,'digital public sphere twitter debate democratic opinion'),
('w_media_C1_31','surveillance capitalism','/sərˈveɪləns ˈkæpɪtəlɪzəm/','noun','감시 자본주의','An economic system built on collecting and selling personal data.','Shoshana Zuboff coined the term {surveillance capitalism}.','쇼샤나 주보프는 감시 자본주의라는 용어를 만들었어요.','surveillance capitalism','C1','media',1,'surveillance capitalism data harvesting Zuboff platform'),
('w_media_C1_32','weaponized information','/ˈwepənaɪzd ɪnfərˈmeɪʃən/','noun','무기화된 정보','Information deliberately distorted to destabilize societies.','Democracies struggle to defend against {weaponized information}.','민주주의는 무기화된 정보에 맞서 싸우고 있어요.','weaponized information','C1','media',1,'weaponized information democracy defense disinformation'),
('w_media_C1_33','credibility cues','/ˌkredɪˈbɪlɪti kjuːz/','noun','신뢰성 단서','Visual or contextual signals that indicate whether information is trustworthy.','Readers use {credibility cues} to judge news reliability.','독자들은 신뢰성 단서를 이용해 뉴스 신뢰도를 판단해요.','credibility cues','C1','media',2,'credibility cues news source trust signal evaluation'),
('w_media_C1_34','transparency reporting','/trænsˈpærənsi rɪˈpɔːrtɪŋ/','noun','투명성 보고','Public disclosure by platforms about their moderation and ad policies.','Regulators now require quarterly {transparency reporting}.','규제당국은 이제 분기별 투명성 보고를 요구해요.','transparency reporting','C1','media',2,'transparency reporting regulation platform accountability'),
('w_media_C1_35','editorial independence','/ˌedɪˈtɔːriəl ˌɪndɪˈpendəns/','noun','편집권 독립','The freedom of journalists to report without interference from owners or advertisers.','Public broadcasters must protect {editorial independence}.','공영 방송은 편집권 독립을 지켜야 해요.','editorial independence','C1','media',1,'editorial independence journalism freedom owner advertiser');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_media_C2_01','semiotics','/ˌsiːmiˈɒtɪks/','noun','기호학','The study of signs, symbols, and their meaning in communication.','Applying {semiotics} to advertising reveals hidden messages.','광고에 기호학을 적용하면 숨겨진 메시지가 드러나요.','semiotics','C2','media',1,'semiotics signs symbols advertising hidden meaning'),
('w_media_C2_02','commodification','/kəˌmɒdɪfɪˈkeɪʃən/','noun','상품화','The process of turning something non-commercial into a market commodity.','The {commodification} of personal data is a defining feature of the internet age.','개인 데이터의 상품화는 인터넷 시대의 결정적 특징이에요.','commodification','C2','media',1,'commodification data personal information market internet'),
('w_media_C2_03','hyperreality','/ˌhaɪpərriˈæləti/','noun','초현실','A condition where the distinction between reality and simulation collapses.','Baudrillard argued that media creates a state of {hyperreality}.','보드리야르는 미디어가 초현실 상태를 만들어낸다고 주장했어요.','hyperreality','C2','media',1,'hyperreality Baudrillard simulation reality media philosophy'),
('w_media_C2_04','simulacrum','/ˌsɪmjʊˈlɑːkrəm/','noun','시뮬라크르','A copy or representation that has no original, replacing reality itself.','Social media presents a {simulacrum} of authentic social life.','소셜 미디어는 진정한 사회생활의 시뮬라크르를 제시해요.','simulacrum','C2','media',1,'simulacrum copy representation social media fake authentic'),
('w_media_C2_05','technocracy','/tekˈnɒkrəsi/','noun','기술 관료제','A system of governance where technology experts hold power.','Silicon Valley''s rise reflects a new digital {technocracy}.','실리콘 밸리의 부상은 새로운 디지털 기술 관료제를 반영해요.','technocracy','C2','media',1,'technocracy silicon valley power governance engineers'),
('w_media_C2_06','post-truth','/poʊst truːθ/','adjective','탈진실의','Relating to circumstances where emotion and belief override objective facts.','We live in a {post-truth} media environment.','우리는 탈진실 미디어 환경 속에 살고 있어요.','post-truth','C2','media',1,'post-truth media era emotion facts belief politics'),
('w_media_C2_07','infosphere','/ˈɪnfoʊsfɪər/','noun','인포스피어','The global environment of information and communication systems.','Luciano Floridi conceptualizes the {infosphere} as our new habitat.','루치아노 플로리디는 인포스피어를 우리의 새로운 서식지로 개념화해요.','infosphere','C2','media',1,'infosphere information environment global digital Floridi'),
('w_media_C2_08','algorithmic governance','/ˌælɡərɪðmɪk ˈɡʌvərnəns/','noun','알고리즘 통치','The use of automated systems to make decisions with public consequences.','Critics argue that {algorithmic governance} lacks democratic accountability.','비평가들은 알고리즘 통치가 민주적 책임을 결여한다고 주장해요.','algorithmic governance','C2','media',1,'algorithmic governance automation policy accountability'),
('w_media_C2_09','deepfake epistemics','/ˈdiːpfeɪk ˌepɪˈstemɪks/','noun','딥페이크 인식론','The study of how synthetic media affects our ability to trust what we perceive.','Scholars of {deepfake epistemics} question the evidentiary value of video.','딥페이크 인식론 학자들은 영상의 증거적 가치에 의문을 제기해요.','deepfake epistemics','C2','media',1,'deepfake truth evidence epistemics philosophy media'),
('w_media_C2_10','Habermasian','/ˌhɑːbərˈmɑːziən/','adjective','하버마스적','Relating to the ideas of Jürgen Habermas, especially the public sphere.','A {Habermasian} analysis reveals how platforms distort rational discourse.','하버마스적 분석은 플랫폼이 어떻게 합리적 담론을 왜곡하는지 드러내요.','Habermasian','C2','media',1,'Habermas public sphere rational discourse philosophy'),
('w_media_C2_11','ontological security','/ˌɒntəˈlɒdʒɪkəl sɪˈkjʊərɪti/','noun','존재론적 안정성','The sense of order and continuity in one''s world, which media can disrupt.','Constant news overload threatens individuals'' {ontological security}.','끊임없는 뉴스 과부하는 개인의 존재론적 안정성을 위협해요.','ontological security','C2','media',1,'ontological security media anxiety information overload'),
('w_media_C2_12','discursive formation','/dɪˈskɜːrsɪv fɔːˈmeɪʃən/','noun','담론 형성체','A group of statements that systematically form the objects they describe (Foucault).','The coverage constitutes a {discursive formation} around criminality.','그 보도는 범죄성에 관한 담론 형성체를 구성해요.','discursive formation','C2','media',1,'discursive formation Foucault media discourse analysis'),
('w_media_C2_13','ideological state apparatus','/ˌaɪdiəˈlɒdʒɪkəl steɪt ˈæpərətəs/','noun','이데올로기적 국가 기구','Althusser''s concept of institutions (including media) that reproduce ruling ideology.','Mass media functions as an {ideological state apparatus}.','대중 매체는 이데올로기적 국가 기구로 기능해요.','ideological state apparatus','C2','media',1,'Althusser ideology state apparatus media television'),
('w_media_C2_14','mediatized politics','/ˈmiːdiətaɪzd ˈpɒlɪtɪks/','noun','미디어화된 정치','The phenomenon of political life being fundamentally shaped by media formats.','Image management is central to {mediatized politics}.','이미지 관리는 미디어화된 정치의 핵심이에요.','mediatized politics','C2','media',1,'mediatized politics image management spin media campaign'),
('w_media_C2_15','networked individualism','/ˈnetwɜːrkt ˌɪndɪˈvɪdʒuəlɪzəm/','noun','네트워크화된 개인주의','A social pattern where people maintain connections through personal networks rather than groups.','Castells described {networked individualism} as the new social operating system.','카스텔스는 네트워크화된 개인주의를 새로운 사회 운영 체계라고 설명했어요.','networked individualism','C2','media',1,'networked individualism Castells social network personal'),
('w_media_C2_16','attention fragmentation','/əˈtenʃən ˌfræɡmenˈteɪʃən/','noun','주의 분산','The breaking up of audience attention across many competing media channels.','{Attention fragmentation} has made mass broadcasting obsolete.','주의 분산은 대규모 방송을 구식으로 만들었어요.','attention fragmentation','C2','media',1,'attention fragmentation multiple screens media distracted'),
('w_media_C2_17','parasocial relationship','/ˌpærəˈsoʊʃəl rɪˈleɪʃənʃɪp/','noun','의사 사회적 관계','A one-sided emotional bond viewers form with media figures.','Audiences form deep {parasocial relationships} with podcasters.','청중은 팟캐스터와 깊은 의사 사회적 관계를 형성해요.','parasocial relationships','C2','media',1,'parasocial relationship youtube podcaster fan bond'),
('w_media_C2_18','technodeterminism','/ˌteknəʊdɪˈtɜːrmɪnɪzəm/','noun','기술 결정론','The belief that technology autonomously drives social and cultural change.','McLuhan''s "the medium is the message" exemplifies {technodeterminism}.','맥루한의 "미디어가 메시지다"는 기술 결정론의 예시예요.','technodeterminism','C2','media',1,'technodeterminism McLuhan medium message technology change'),
('w_media_C2_19','platform imperialism','/ˈplætfɔːrm ɪmˈpɪəriəlɪzəm/','noun','플랫폼 제국주의','The dominance of Western digital platforms over global information flows.','Scholars debate whether TikTok challenges {platform imperialism}.','학자들은 틱톡이 플랫폼 제국주의에 도전하는지 논쟁해요.','platform imperialism','C2','media',1,'platform imperialism TikTok Western digital global power'),
('w_media_C2_20','noise-to-signal ratio','/nɔɪz tə ˈsɪɡnəl ˈreɪʃioʊ/','noun','잡음 대 신호 비율','The proportion of irrelevant or low-quality content relative to valuable information.','The high {noise-to-signal ratio} online makes quality journalism vital.','온라인의 높은 잡음 대 신호 비율은 양질의 저널리즘을 필수로 만들어요.','noise-to-signal ratio','C2','media',1,'noise signal ratio information quality journalism online'),
('w_media_C2_21','second-order media effects','/ˈsekənd ˈɔːrdər ˈmiːdiə ɪˈfekts/','noun','2차 미디어 효과','Indirect social changes caused by media exposure beyond the intended message.','Long-term {second-order media effects} are difficult to measure.','장기적인 2차 미디어 효과는 측정하기 어려워요.','second-order media effects','C2','media',2,'second order effects media long term social change'),
('w_media_C2_22','performative contradiction','/pərˈfɔːrmətɪv ˌkɒntrəˈdɪkʃən/','noun','수행적 자기 모순','A statement that undermines the very norms it appeals to in order to be made.','A media company claiming to fight censorship while blocking content commits a {performative contradiction}.','검열과 싸운다고 주장하면서 콘텐츠를 차단하는 미디어 기업은 수행적 자기 모순을 범해요.','performative contradiction','C2','media',2,'performative contradiction hypocrisy media platform censorship'),
('w_media_C2_23','digital hermeneutics','/ˈdɪdʒɪtəl ˌhɜːrməˈnjuːtɪks/','noun','디지털 해석학','The interpretation of digital texts and media in cultural context.','Scholars of {digital hermeneutics} study how algorithms shape reading.','디지털 해석학 학자들은 알고리즘이 독서를 어떻게 형성하는지 연구해요.','digital hermeneutics','C2','media',2,'digital hermeneutics text meaning algorithm reading culture'),
('w_media_C2_24','epistemic crisis','/ˌepɪˈstiːmɪk ˈkraɪsɪs/','noun','인식론적 위기','A breakdown in shared standards for establishing truth or knowledge.','Widespread disinformation has produced an {epistemic crisis}.','광범위한 허위정보가 인식론적 위기를 초래했어요.','epistemic crisis','C2','media',1,'epistemic crisis truth knowledge breakdown disinformation'),
('w_media_C2_25','communicative capitalism','/kəˈmjuːnɪkətɪv ˈkæpɪtəlɪzəm/','noun','소통적 자본주의','The idea that digital communication has been absorbed into capitalist exchange.','Jodi Dean''s concept of {communicative capitalism} explains the addictive logic of social media.','조디 딘의 소통적 자본주의 개념은 소셜 미디어의 중독 논리를 설명해요.','communicative capitalism','C2','media',2,'communicative capitalism social media engagement addiction loop'),
('w_media_C2_26','ideological interpellation','/ˌaɪdiəˈlɒdʒɪkəl ˌɪntɜːrpəˈleɪʃən/','noun','이데올로기적 호명','Althusser''s concept of how media "hails" individuals into ideological subject positions.','Advertising functions through {ideological interpellation}.','광고는 이데올로기적 호명을 통해 작동해요.','ideological interpellation','C2','media',2,'interpellation Althusser ideology advertising subject media'),
('w_media_C2_27','cultural hegemony','/ˈkʌltʃərəl hɪˈɡeməni/','noun','문화적 헤게모니','Gramsci''s concept of how a dominant class maintains power through cultural institutions including media.','Television historically reinforced {cultural hegemony}.','텔레비전은 역사적으로 문화적 헤게모니를 강화해왔어요.','cultural hegemony','C2','media',1,'cultural hegemony Gramsci media television dominant ideology'),
('w_media_C2_28','media ecology','/ˈmiːdiə ɪˈkɒlədʒi/','noun','미디어 생태학','The study of media environments and how they affect human perception and society.','{Media ecology} examines how screens reshape attention spans.','미디어 생태학은 화면이 어떻게 주의력 범위를 재형성하는지 검토해요.','media ecology','C2','media',2,'media ecology environment screen attention McLuhan society'),
('w_media_C2_29','semiotic democracy','/ˌsiːmiˈɒtɪk dɪˈmɒkrəsi/','noun','기호학적 민주주의','The idea that audiences actively reinterpret media texts for their own purposes.','Fan communities enact a kind of {semiotic democracy}.','팬 커뮤니티는 일종의 기호학적 민주주의를 실천해요.','semiotic democracy','C2','media',2,'semiotic democracy fan interpretation media text audience'),
('w_media_C2_30','hyper-personalization','/ˌhaɪpər ˌpɜːrsənəlaɪˈzeɪʃən/','noun','초개인화','Extreme tailoring of media content to individual users via data analysis.','The danger of {hyper-personalization} is the collapse of shared reality.','초개인화의 위험은 공유된 현실의 붕괴예요.','hyper-personalization','C2','media',1,'hyper personalization algorithm individual reality collapse'),
('w_media_C2_31','digital sovereignty','/ˈdɪdʒɪtəl ˈsɒvrənti/','noun','디지털 주권','The right of states or individuals to control their own digital environments.','European regulation is driven by a vision of {digital sovereignty}.','유럽의 규제는 디지털 주권 비전에 의해 추진되고 있어요.','digital sovereignty','C2','media',1,'digital sovereignty Europe regulation data control GDPR'),
('w_media_C2_32','technological solutionism','/ˌteknəˈlɒdʒɪkəl ˈsoʊluːʃənɪzəm/','noun','기술 만능주의','The belief that every social problem can be solved with a technological fix.','Morozov criticized Silicon Valley''s {technological solutionism}.','모로조프는 실리콘 밸리의 기술 만능주의를 비판했어요.','technological solutionism','C2','media',2,'technological solutionism Morozov Silicon Valley fix problem'),
('w_media_C2_33','critical data studies','/ˈkrɪtɪkəl ˈdeɪtə ˈstʌdiz/','noun','비판적 데이터 연구','An academic field examining the political and ethical dimensions of data collection.','Scholars in {critical data studies} interrogate platform surveillance.','비판적 데이터 연구 학자들은 플랫폼 감시를 문제 삼아요.','critical data studies','C2','media',2,'critical data studies surveillance platform ethics academic'),
('w_media_C2_34','post-digital','/poʊst ˈdɪdʒɪtəl/','adjective','포스트디지털의','Relating to a culture where digital technology is so pervasive it is no longer remarkable.','We live in a {post-digital} media landscape.','우리는 포스트디지털 미디어 환경 속에 살고 있어요.','post-digital','C2','media',2,'post-digital ubiquitous technology pervasive media culture'),
('w_media_C2_35','legitimation crisis','/ˌledʒɪtɪˈmeɪʃən ˈkraɪsɪs/','noun','정당성 위기','A breakdown of trust in social institutions, accelerated by media exposure.','Social media has triggered a {legitimation crisis} for mainstream journalism.','소셜 미디어가 주류 저널리즘의 정당성 위기를 촉발했어요.','legitimation crisis','C2','media',1,'legitimation crisis journalism trust mainstream media decline');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_A1_01','money','/ˈmʌni/','noun','돈','Coins or notes used to pay for things.','Do you have {money} with you?','돈 가지고 있어요?','money','A1','economy',1,'money coins bills wallet cash'),
('w_economy_A1_02','price','/praɪs/','noun','가격','The amount of money required to buy something.','What is the {price} of this jacket?','이 재킷의 가격이 얼마예요?','price','A1','economy',1,'price tag shopping retail store'),
('w_economy_A1_03','buy','/baɪ/','verb','사다','To get something by paying money for it.','I want to {buy} a new phone.','새 휴대폰을 사고 싶어요.','buy','A1','economy',1,'shopping buying store purchase'),
('w_economy_A1_04','sell','/sel/','verb','팔다','To exchange something for money.','They {sell} fresh vegetables here.','여기서 신선한 채소를 팔아요.','sell','A1','economy',1,'market selling vendor stall produce'),
('w_economy_A1_05','pay','/peɪ/','verb','지불하다','To give money in exchange for goods or services.','Can I {pay} by credit card?','신용카드로 계산할 수 있나요?','pay','A1','economy',1,'payment cashier counter card terminal'),
('w_economy_A1_06','cheap','/tʃiːp/','adjective','저렴한','Low in price;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_A2_01','tax','/tæks/','noun','세금','Money that must be paid to the government.','The price includes {tax}.','가격에 세금이 포함되어 있어요.','tax','A2','economy',1,'tax form documents government finance'),
('w_economy_A2_02','income','/ˈɪnkʌm/','noun','수입','Money received regularly from work or investments.','My monthly {income} is enough to cover my expenses.','월 수입이 생활비를 충당하기에 충분해요.','income','A2','economy',1,'income salary paycheck money earning'),
('w_economy_A2_03','budget','/ˈbʌdʒɪt/','noun','예산','A plan for how to spend money.','I need to stick to my {budget} this month.','이번 달은 예산을 지켜야 해요.','budget','A2','economy',1,'budget planning notebook spreadsheet finance'),
('w_economy_A2_04','profit','/ˈprɒfɪt/','noun','이익','Money made after costs are paid.','The company made a big {profit} last year.','그 회사는 작년에 큰 이익을 냈어요.','profit','A2','economy',1,'profit growth chart business success'),
('w_economy_A2_05','loan','/loʊn/','noun','대출','Money borrowed from a bank that must be repaid.','I took out a {loan} to buy my car.','차를 사려고 대출을 받았어요.','loan','A2','economy',1,'loan bank signature document agreement'),
('w_economy_A2_06','credit','/ˈkredɪt/','noun','신용;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_B1_01','inflation','/ɪnˈfleɪʃən/','noun','인플레이션','A general increase in prices over time.','High {inflation} is reducing people''s purchasing power.','높은 인플레이션이 구매력을 줄이고 있어요.','inflation','B1','economy',1,'inflation prices rising chart graph economy'),
('w_economy_B1_02','recession','/rɪˈseʃən/','noun','경기 침체','A period of economic decline lasting several months.','The country entered a {recession} last year.','그 나라는 작년에 경기 침체에 들어갔어요.','recession','B1','economy',1,'recession economy decline graph business'),
('w_economy_B1_03','interest rate','/ˈɪntrəst reɪt/','noun','금리','The percentage charged on borrowed money.','The central bank raised the {interest rate}.','중앙은행이 금리를 올렸어요.','interest rate','B1','economy',1,'interest rate central bank chart percentage'),
('w_economy_B1_04','stock','/stɒk/','noun','주식','A share in the ownership of a company.','She owns {stock} in several tech companies.','그녀는 여러 기술 회사의 주식을 가지고 있어요.','stock','B1','economy',1,'stock market trading screen ticker'),
('w_economy_B1_05','market','/ˈmɑːrkɪt/','noun','시장 (금융)','The trade in a particular type of commodity.','The housing {market} has slowed down.','주택 시장이 둔화되었어요.','market','B1','economy',1,'financial market trading floor investors'),
('w_economy_B1_06','GDP','/ˌdʒiː diː ˈpiː/','noun','국내총생산','Gross Domestic Product — the total value of goods and services produced.','The country''s {GDP} grew by three percent.','그 나라의 GDP가 3% 성장했어요.','GDP','B1','economy',1,'GDP economy data chart growth country'),
('w_economy_B1_07','fiscal','/ˈfɪskəl/','adjective','재정의','Relating to government revenue and expenditure.','The government announced its new {fiscal} policy.','정부가 새 재정 정책을 발표했어요.','fiscal','B1','economy',2,'fiscal policy government budget parliament'),
('w_economy_B1_08','monetary','/ˈmɒnɪtəri/','adjective','통화의','Relating to money or currency in circulation.','The central bank uses {monetary} tools to control inflation.','중앙은행은 인플레이션을 조절하기 위해 통화 수단을 사용해요.','monetary','B1','economy',2,'monetary policy central bank board meeting'),
('w_economy_B1_09','trade','/treɪd/','noun','무역;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_B2_01','deficit','/ˈdefɪsɪt/','noun','적자, 결손','When expenditure exceeds revenue.','The government ran a large budget {deficit}.','정부는 큰 재정 적자를 기록했어요.','deficit','B2','economy',1,'deficit budget government spending debt chart'),
('w_economy_B2_02','quantitative easing','/ˌkwɒntɪteɪtɪv ˈiːzɪŋ/','noun','양적 완화','A monetary policy where central banks buy assets to inject money.','The Fed used {quantitative easing} to stimulate the economy.','연준은 경제를 부양하기 위해 양적 완화를 사용했어요.','quantitative easing','B2','economy',1,'quantitative easing central bank policy money'),
('w_economy_B2_03','liquidity','/lɪˈkwɪdɪti/','noun','유동성','The ease of converting assets to cash.','The bank faces a serious {liquidity} problem.','그 은행은 심각한 유동성 문제에 직면했어요.','liquidity','B2','economy',1,'liquidity cash flow bank finance chart'),
('w_economy_B2_04','equity','/ˈekwɪti/','noun','자기자본;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_economy_C1_01','macroeconomics','/ˌmækroʊˌiːkəˈnɒmɪks/','noun','거시경제학','The branch of economics studying large-scale economic factors.','{Macroeconomics} focuses on GDP, inflation, and employment as a whole.','거시경제학은 GDP, 인플레이션, 고용 전체에 초점을 맞춰요.','macroeconomics','C1','economy',1,'macroeconomics lecture university economics textbook'),
('w_economy_C1_02','microeconomics','/ˌmaɪkroʊˌiːkəˈnɒmɪks/','noun','미시경제학','The branch of economics studying individual consumers and firms.','{Microeconomics} examines how prices are set in individual markets.','미시경제학은 개별 시장에서 가격이 어떻게 결정되는지 살펴봐요.','microeconomics','C1','economy',1,'microeconomics individual market supply demand graph'),
('w_economy_C1_03','stagflation','/stæɡˈfleɪʃən/','noun','스태그플레이션','A simultaneous occurrence of stagnation and inflation.','Policymakers struggled to address {stagflation} in the 1970s.','정책 입안자들은 1970년대 스태그플레이션 해결에 애를 먹었어요.','stagflation','C1','economy',1,'stagflation crisis newspaper headline economic history'),
('w_economy_C1_04','arbitrage','/ˈɑːrbɪtrɑːʒ/','noun','차익거래','Profiting from price differences in different markets.','Currency {arbitrage} requires speed and capital.','통화 차익거래는 속도와 자본이 필요해요.','arbitrage','C1','economy',2,'arbitrage trading screens currency price difference'),
('w_economy_C1_05','austerity','/ɒˈsterɪti/','noun','긴축 재정 정책','Severe economic policies to reduce government debt.','The IMF imposed strict {austerity} measures on the country.','IMF는 그 나라에 엄격한 긴축 조치를 부과했어요.','austerity','C1','economy',1,'austerity IMF government cuts protest economy'),
('w_economy_C1_06','deregulation','/ˌdiːˌreɡjʊˈleɪʃən/','noun','규제 완화','Reduction of government rules over an industry.','Financial {deregulation} in the 1980s allowed banks greater freedom.','1980년대 금융 규제 완화로 은행들은 더 큰 자유를 얻었어요.','deregulation','C1','economy',1,'deregulation finance bank building government law'),
('w_economy_C1_07','privatization','/ˌpraɪvətaɪˈzeɪʃən/','noun','민영화','Transferring a public service to private ownership.','The {privatization} of the railway was controversial.','철도 민영화는 논란이 됐어요.','privatization','C1','economy',1,'privatization railway public private corporation'),
('w_economy_C1_08','subsidy','/ˈsʌbsɪdi/','noun','보조금 (정책적)','Government financial support to encourage an activity.','Agricultural {subsidies} keep food prices stable.','농업 보조금이 식품 가격을 안정적으로 유지해요.','subsidy','C1','economy',1,'subsidy agriculture government support farm policy'),
('w_economy_C1_09','tariff','/ˈtærɪf/','noun','관세','A tax on imported goods.','The government imposed a twenty percent {tariff} on steel.','정부는 철강에 20% 관세를 부과했어요.','tariff','C1','economy',1,'tariff trade customs import border tax'),
('w_economy_C1_10','cartel','/kɑːrˈtel/','noun','카르텔','A group of companies agreeing to fix prices.','The oil {cartel} agreed to cut production.','석유 카르텔이 생산을 줄이기로 합의했어요.','cartel','C1','economy',1,'cartel oil OPEC meeting agreement energy'),
('w_economy_C1_11','oligopoly','/ˌɒlɪˈɡɒpəli/','noun','과점','A market controlled by a small number of firms.','The telecom sector is an {oligopoly} in most countries.','통신 분야는 대부분의 나라에서 과점이에요.','oligopoly','C1','economy',2,'oligopoly few companies market dominance'),
('w_economy_C1_12','externality','/ˌekstɜːrˈnælɪti/','noun','외부 효과','A cost or benefit affecting a third party outside a transaction.','Pollution is a classic negative {externality}.','오염은 전형적인 부정적 외부 효과예요.','externality','C1','economy',2,'externality pollution factory smoke environment'),
('w_economy_C1_13','fiscal stimulus','/ˈfɪskəl ˈstɪmjʊləs/','noun','재정 부양책','Government spending to boost economic activity.','The government announced a large {fiscal stimulus} package.','정부가 대규모 재정 부양 패키지를 발표했어요.','fiscal stimulus','C1','economy',1,'fiscal stimulus government spending infrastructure project'),
('w_economy_C1_14','central bank','/ˈsentrəl bæŋk/','noun','중앙은행','The national institution managing monetary policy.','The {central bank} raised rates by fifty basis points.','중앙은행이 기준금리를 50bp 인상했어요.','central bank','C1','economy',1,'central bank federal reserve building architecture'),
('w_economy_C1_15','austerity measure','/ɒˈsterɪti ˈmeʒər/','noun','긴축 조치','A specific policy action to cut government spending.','New {austerity measures} sparked nationwide protests.','새 긴축 조치가 전국적인 시위를 촉발시켰어요.','austerity measure','C1','economy',2,'austerity protest street signs economy crisis'),
('w_economy_C1_16','structural reform','/ˈstrʌktʃərəl rɪˈfɔːrm/','noun','구조 개혁','Long-term policy changes to improve economic efficiency.','The IMF called for deep {structural reforms}.','IMF는 심도 있는 구조 개혁을 촉구했어요.','structural reform','C1','economy',2,'structural reform policy government parliament document'),
('w_economy_C1_17','protectionism','/prəˈtekʃənɪzəm/','noun','보호무역주의','Economic policy restricting imports to protect domestic industry.','Rising {protectionism} threatens global trade.','높아지는 보호무역주의가 세계 무역을 위협하고 있어요.','protectionism','C1','economy',2,'protectionism trade wall tariff border policy'),
('w_economy_C1_18','moral hazard','/ˈmɒrəl ˈhæzərd/','noun','도덕적 해이','The tendency to take more risk because of protection from consequences.','Bank bailouts create {moral hazard}.','은행 구제금융은 도덕적 해이를 만들어요.','moral hazard','C1','economy',2,'moral hazard risk banking finance responsibility'),
('w_economy_C1_19','comparative advantage','/kəmˈpærətɪv ədˈvɑːntɪdʒ/','noun','비교우위','The ability to produce a good at a lower opportunity cost than another.','Trade is based on each country''s {comparative advantage}.','무역은 각 나라의 비교우위를 기반으로 해요.','comparative advantage','C1','economy',2,'comparative advantage trade global specialization'),
('w_economy_C1_20','purchasing power','/ˈpɜːrtʃəsɪŋ ˌpaʊər/','noun','구매력','The amount of goods a unit of currency can buy.','Inflation erodes {purchasing power} over time.','인플레이션은 시간이 지남에 따라 구매력을 잠식해요.','purchasing power','C1','economy',2,'purchasing power money shopping cart inflation'),
('w_economy_C1_21','free market','/friː ˈmɑːrkɪt/','noun','자유 시장','An economic system with minimal government intervention.','A {free market} allocates resources through supply and demand.','자유 시장은 수요와 공급을 통해 자원을 배분해요.','free market','C1','economy',1,'free market economy trade global business'),
('w_economy_C1_22','planned economy','/plænd ɪˈkɒnəmi/','noun','계획 경제','An economy in which production is controlled by the state.','A {planned economy} aims to distribute resources equally.','계획 경제는 자원을 균등하게 배분하는 것을 목표로 해요.','planned economy','C1','economy',2,'planned economy government factory state control'),
('w_economy_C1_23','sovereign debt','/ˈsɒvrən det/','noun','국가 채무','Money owed by a national government.','Rising {sovereign debt} alarmed investors.','증가하는 국가 채무가 투자자들을 놀라게 했어요.','sovereign debt','C1','economy',2,'sovereign debt government bond finance crisis'),
('w_economy_C1_24','crowding out','/ˈkraʊdɪŋ aʊt/','noun','구축 효과','When government borrowing reduces private sector investment.','Heavy state spending can cause {crowding out}.','과도한 국가 지출은 구축 효과를 일으킬 수 있어요.','crowding out','C1','economy',3,'crowding out government spending private sector'),
('w_economy_C1_25','natural monopoly','/ˈnætʃərəl məˈnɒpəli/','noun','자연독점','A market dominated by a single firm due to high entry costs.','Utilities are often considered {natural monopolies}.','공익 서비스는 종종 자연독점으로 여겨져요.','natural monopoly','C1','economy',2,'natural monopoly utility infrastructure power'),
('w_economy_C1_26','price elasticity','/praɪs ˌiːlæˈstɪsɪti/','noun','가격 탄력성','How sensitive demand is to a change in price.','Cigarettes have low {price elasticity} of demand.','담배는 수요의 가격 탄력성이 낮아요.','price elasticity','C1','economy',2,'price elasticity demand graph economics curve'),
('w_economy_C1_27','market failure','/ˈmɑːrkɪt ˈfeɪljər/','noun','시장 실패','When a free market does not efficiently allocate resources.','Pollution is a sign of {market failure}.','오염은 시장 실패의 신호예요.','market failure','C1','economy',2,'market failure environment pollution government'),
('w_economy_C1_28','balance of payments','/ˈbæləns əv ˈpeɪmənts/','noun','국제수지','A record of all transactions between a country and the world.','A deficit in the {balance of payments} weakens the currency.','국제수지 적자는 통화를 약화시켜요.','balance of payments','C1','economy',2,'balance of payments trade data statistics report'),
('w_economy_C1_29','lender of last resort','/ˈlendər əv lɑːst rɪˈzɔːrt/','noun','최종 대부자','An institution that provides emergency funds to banks.','The central bank acted as the {lender of last resort}.','중앙은행이 최종 대부자로 역할을 했어요.','lender of last resort','C1','economy',3,'central bank emergency loan crisis finance'),
('w_economy_C1_30','Keynesian economics','/ˈkeɪnziən ˌiːkəˈnɒmɪks/','noun','케인즈 경제학','Economic theory advocating government intervention to stabilize economies.','{Keynesian economics} supports deficit spending during recessions.','케인즈 경제학은 경기 침체 시 적자 지출을 지지해요.','Keynesian economics','C1','economy',2,'Keynes economics book theory government spending'),
('w_economy_C1_31','supply-side economics','/səˈplaɪ saɪd ˌiːkəˈnɒmɪks/','noun','공급 중심 경제학','Economic theory focusing on increasing production.','{Supply-side economics} promotes tax cuts for businesses.','공급 중심 경제학은 기업을 위한 세금 감면을 촉진해요.','supply-side economics','C1','economy',2,'supply side tax cut business production economics'),
('w_economy_C1_32','opportunity cost','/ˌɒpəˈtjuːnɪti kɒst/','noun','기회 비용','The value of the next best option forgone.','Going to university has an {opportunity cost} of lost wages.','대학 진학에는 포기된 임금이라는 기회 비용이 있어요.','opportunity cost','C1','economy',2,'opportunity cost decision choice trade-off economics'),
('w_economy_C1_33','hyperinflation','/ˌhaɪpərɪnˈfleɪʃən/','noun','초인플레이션','Extremely rapid and out-of-control price increases.','Zimbabwe suffered severe {hyperinflation} in the 2000s.','짐바브웨는 2000년대 심각한 초인플레이션을 겪었어요.','hyperinflation','C1','economy',2,'hyperinflation banknotes wheelbarrow crisis Zimbabwe'),
('w_economy_C1_34','fiscal consolidation','/ˈfɪskəl kənsɒlɪˈdeɪʃən/','noun','재정 건전화','Reducing budget deficits through spending cuts or tax rises.','{Fiscal consolidation} was necessary to restore investor confidence.','재정 건전화는 투자자 신뢰 회복에 필요했어요.','fiscal consolidation','C1','economy',2,'fiscal consolidation budget government documents finance'),
('w_economy_C1_35','income inequality','/ˈɪnkʌm ˌɪnɪˈkwɒlɪti/','noun','소득 불평등','The unequal distribution of income in society.','Rising {income inequality} is a global concern.','증가하는 소득 불평등은 세계적인 우려예요.','income inequality','C1','economy',1,'income inequality wealth gap poverty rich poor');
